from pybricks.hubs import PrimeHub
from pybricks.parameters import Axis, Direction, Port, Stop
from pybricks.pupdevices import Motor
from pybricks.robotics import DriveBase
from pybricks.tools import StopWatch, multitask, run_task, wait

from utility import steer_turn

# Set up all devices.
prime_hub = PrimeHub(top_side=Axis.Z, front_side=Axis.X)
watch = StopWatch()
rightsheel = Motor(Port.C, Direction.CLOCKWISE)
leftwheel = Motor(Port.D, Direction.COUNTERCLOCKWISE)
drive_base = DriveBase(leftwheel, rightsheel, 62.4, 80)
left_motor = Motor(Port.B, Direction.COUNTERCLOCKWISE)
right_motor = Motor(Port.F, Direction.COUNTERCLOCKWISE)

async def subtask():
    await left_motor.run_until_stalled(-500, Stop.HOLD, 50)
    left_motor.reset_angle(0)

async def subtask2():
    await right_motor.run_until_stalled(500, Stop.HOLD, 50)
    right_motor.reset_angle(0)

async def subtask3():
    await drive_base.straight(-10)
    drive_base.reset(0, 0)
    drive_base.use_gyro(True)
    drive_base.settings(straight_speed=800)
    drive_base.settings(straight_acceleration=800)
    await drive_base.straight(760)

async def subtask4():
    await left_motor.run_target(500, 130)
    await wait(10)
    # Release ores
    await drive_base.turn(50)

async def subtask5():
    await left_motor.run_target(500, 130)
    await wait(10)
    # Release ores
    await drive_base.turn(50)

async def subtask6():
    await multitask(
        right_motor.run_target(1000, 0),
        subtask4(),
    )

async def subtask7():
    await wait(5000)
    print('Lift millstone timeout')

async def subtask8():
    drive_base.settings(turn_rate=360)
    drive_base.settings(turn_acceleration=750)
    await drive_base.turn(-90 - prime_hub.imu.heading())
    await steer_turn(drive_base, leftwheel, rightsheel, -90)

async def subtask9():
    await drive_base.turn(0 - prime_hub.imu.heading())
    await steer_turn(drive_base, leftwheel, rightsheel, 0, False, 300, 3)

async def main():
    # William Chen
    watch.reset()
    print('Battery', prime_hub.battery.voltage(), sep=", ")
    await multitask(
        subtask(),
        subtask2(),
        subtask3(),
    )
    # Heavy lifting
    await right_motor.run_angle(1000, -1200, Stop.COAST)
    await multitask(
        subtask6(),
        subtask7(),
        race=True,
    )
    # flip table
    await multitask(
        left_motor.run_target(500, 0),
        drive_base.straight(-70),
    )
    await multitask(
        subtask8(),
        left_motor.run_target(1000, 0),
    )
    await drive_base.straight(-470)
    await multitask(
        right_motor.run_target(500, -500),
        subtask9(),
    )


run_task(main())